import{_ as a,o as b,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"清风决","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/功法/清风决.md","filePath":"4.资源分区/2.改造与功法/功法/清风决.md"}'),o={name:"4.资源分区/2.改造与功法/功法/清风决.md"};function p(d,e,l,_,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"清风决",tabindex:"-1"},[n("清风决 "),r("a",{class:"header-anchor",href:"#清风决","aria-label":'Permalink to "清风决"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序002")])])],-1),s('<h1 id="清风决-1" tabindex="-1">清风决 <a class="header-anchor" href="#清风决-1" aria-label="Permalink to &quot;清风决&quot;">​</a></h1><p>清风决<br> 介绍：古修士感悟清风，格物致知后所创的功法，现如今只是修真界一寻常功法，或有传闻，有修士修炼此法至大成，亦可称一方霸主。<br> 魔幻本质<br> 注：表达——专业：清风诀</p><p>D级：尘世<br> 清风徐徐，过山河，厉人间。<br> 特性：凡尘清风（三特性）<br> 凡尘清风：清风修士，炼于凡尘，每个影片结束后你的风度相关检定获得2内在加值，这个效果最多提供12点内在加值。并获得能量池：清风真气<br> 清风真气：感知+风度，东方通用能量池<br> 基础用法：每轮一次，在受到攻击时，可以支付1清风真气，在本次检定获得1点防御上的环境加值<br> 恢复方式：<br> 当处于无风环境，如室内、飞船内部时，每进行一次短休息可以恢复上限等同于四分之一风度属性（向下取整）的清风真气<br> 当处于微风环境，如室内窗户旁，每进行一次短休息可以恢复等同于二分之一风度属性（向下取整）的清风真气<br> 当处于中等风环境，每进行一次短休息可以恢复等同于风度属性的清风真气<br> 当处于强风环境时，每进行一次短休息可以恢复等同于风度+感知属性的清风真气<br> 每日一次，在短休息时进行冥想，可以两倍的速度进行恢复<br> 此外，当处于中等风及以上环境进行长休息时，会恢复等同于上限的清风真气。<br> 每日恢复的清风真气不得超过上限的三倍。</p><p>C级：随风<br> 随风而行，顺天道而为<br> 特性：随风，吸风饮露<br> 随风：与风同行，寻求天理， 当你风度上的附加成功达到以下数值时，你依次获得以下能力：<br> 1：你的攻击获得法破<br> 2：你获得灵感视觉<br> 3：你获得普通飞行能力<br> 4、你的飞行能力提升一级机动性<br> 5、你的飞行能力提升一级机动性<br> 当你的功法等级达到B级时你的风度相关检定获得8加骰<br> 吸风饮露：你无需饮食，也无需休息，并获得全环境呼吸能力</p><p>B级：无尘<br> 身在尘世，道心无尘<br> 特性：道心，无尘<br> 道心：你的风度相关检定获得等同于感知的修行加值。<br> 无尘：清风真气额外提升等同于风度+感知属性的上限</p><p>A级：风起<br> 一日同风起，扶摇直上九万里<br> 特性：同风起，登寰宇<br> 同风起：你免疫等同功法等级的环境来源的负面效果，每回合开始时，你获得4点AP以使用自身具有的能力。<br> 登寰宇：你的移动速度提升风度*10米；你在风度相关检定额外获得等同于风度属性的修行加值</p><p>S级：清风<br> 君子之德风，小人之德草，草上之风必偃<br> 特性：风行草偃；得道（双特性，四选一）<br> 风行草偃：每轮2次，可以让你的一次风度相关检定成功数增加一半<br> 得道：购买时选择以下四个特性之一获得，选择后不得更改。<br> 风绿江南：每轮一次，你可以使用一个标准动作支付18点清风真气，令半径200M范围内所有友方角色立刻恢复等同于你风度属性的生命值，医疗点为风度*12。此外，每场战斗结束后（或15分钟/一场景）恢复医疗点至上限。<br> 古木晴风：每轮一次，你可以一个移动动作支付18点清风真气，消除自身等同风度属性一半（向下取整）的异常点数（可以治愈三至四档异常点），医疗点数为风度*12。此外，一影片一次，当你死亡时，立刻在原地复活，这是S级命运来源的复活效果。<br> 叶落风吹：使用标准动作发动，对半径700M范围内所有敌人发动一次攻击，DP公式为：风度+表达+专业：清风诀+专业：魔力爆发+其他加值（如果有），意志豁免，发动前你可以选择让这次攻击附带即死/持续一小时的石化/持续一小时的睡眠（无法唤醒）效果（三选一，只能选择其中一个效果对所有命中目标生效），受到这个技能效果影响的角色在效果结束前不会再次受到这个效果的影响。<br> 冷风缠雪：你的攻击造成韧性伤害，你的表达/社交（购买时选择）技能相关检定获得【传奇】特性</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
